def CurrentHolderNeverFenced():
    for db in DBS:
        if holder[db] != None and (holder[db] in fenced[db]):
            return False
    return True

# Only nodes that are actually alive ever run anything.

def OnlyAliveNodesRun():
    for db in DBS:
        for m in runners[db]:
            if not alive[m]:
                return False
    return True

# The design's stated worst case, a transient double-run, is
# reachable in the model.

def Converged():
    for db in DBS:
        expected = ""
        for r in RANK[db]:
            if expected == "" and alive[r]:
                expected = r
        if expected == "":
            if len(runners[db]) != 0:
                return False
        else:
            if runners[db] != [expected]:
                return False
            if holder[db] != expected:
                return False
        if len(fenced[db]) != 0:
            return False
    return True
